import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { link, navigate } from 'decantr/router';
import { Button, icon } from 'decantr/components';

code.example:
function LoginForm({ onSubmit, error }) {
  const { div, form, h1, p, input, label, span } = tags;
  const [email, setEmail] = createSignal('');
  const [password, setPassword] = createSignal('');
  const [showPw, setShowPw] = createSignal(false);
  const [loading, setLoading] = createSignal(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    await onSubmit({ email: email(), password: password() });
    setLoading(false);
  };

  return div({ class: css('carbon-card _p8 _maxw[400px] _wfull') },
    div({ class: css('_tc _mb6') },
      h1({ class: css('_heading3 _mb2') }, 'Welcome back'),
      p({ class: css('_fgmuted') }, 'Sign in to your account')
    ),
    form({ class: css('_flex _col _gap4'), onsubmit: handleSubmit },
      error ? div({ class: css('_p3 _r2 _bgDanger/10 _fgDanger _textsm') }, error) : null,
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Email'),
        input({
          type: 'email',
          class: css('carbon-input _p2 _r2'),
          value: email(),
          oninput: (e) => setEmail(e.target.value),
          required: true
        })
      ),
      div({ class: css('_flex _col _gap1') },
        div({ class: css('_flex _jcsb') },
          label({ class: css('_textsm _font500') }, 'Password'),
          link({ href: '/forgot-password', class: css('_textsm _fgPrimary') }, 'Forgot?')
        ),
        div({ class: css('_relative') },
          input({
            type: showPw() ? 'text' : 'password',
            class: css('carbon-input _p2 _r2 _wfull _pr10'),
            value: password(),
            oninput: (e) => setPassword(e.target.value),
            required: true
          }),
          Button({
            type: 'button',
            variant: 'ghost',
            size: 'xs',
            class: css('_absolute _right2 _top[50%] _translate[0,-50%]'),
            onclick: () => setShowPw(!showPw())
          }, icon(showPw() ? 'eye-off' : 'eye', { size: '16' }))
        )
      ),
      Button({ type: 'submit', variant: 'primary', class: css('_wfull'), disabled: loading() },
        loading() ? 'Signing in...' : 'Sign In'
      )
    ),
    div({ class: css('_flex _aic _gap4 _my6') },
      div({ class: css('_flex1 _h[1px] _bgBorder') }),
      span({ class: css('_textsm _fgmuted') }, 'or continue with'),
      div({ class: css('_flex1 _h[1px] _bgBorder') })
    ),
    div({ class: css('_flex _gap3') },
      Button({ variant: 'outline', class: css('_flex1') }, icon('google'), 'Google'),
      Button({ variant: 'outline', class: css('_flex1') }, icon('github'), 'GitHub')
    ),
    p({ class: css('_tc _mt6 _textsm _fgmuted') },
      "Don't have an account? ",
      link({ href: '/register', class: css('_fgPrimary _font500') }, 'Sign up')
    )
  );
}

