function RegisterForm({ onSubmit }) {
  const { div, form, h1, p, input, label } = tags;
  const [name, setName] = createSignal('');
  const [email, setEmail] = createSignal('');
  const [password, setPassword] = createSignal('');

  const strength = () => {
    const pw = password();
    if (pw.length < 8) return { level: 0, label: 'Too short', color: 'danger' };
    const has = { upper: /[A-Z]/.test(pw), lower: /[a-z]/.test(pw), num: /[0-9]/.test(pw), special: /[^A-Za-z0-9]/.test(pw) };
    const score = Object.values(has).filter(Boolean).length;
    if (score <= 2) return { level: 1, label: 'Weak', color: 'danger' };
    if (score === 3) return { level: 2, label: 'Medium', color: 'warning' };
    return { level: 3, label: 'Strong', color: 'success' };
  };

  return div({ class: css('carbon-card _p8 _maxw[400px] _wfull') },
    div({ class: css('_tc _mb6') },
      h1({ class: css('_heading3 _mb2') }, 'Create account'),
      p({ class: css('_fgmuted') }, 'Start your free trial')
    ),
    form({ class: css('_flex _col _gap4'), onsubmit: (e) => { e.preventDefault(); onSubmit({ name: name(), email: email(), password: password() }); } },
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Name'),
        input({ type: 'text', class: css('carbon-input _p2 _r2'), value: name(), oninput: (e) => setName(e.target.value), required: true })
      ),
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Email'),
        input({ type: 'email', class: css('carbon-input _p2 _r2'), value: email(), oninput: (e) => setEmail(e.target.value), required: true })
      ),
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Password'),
        input({ type: 'password', class: css('carbon-input _p2 _r2'), value: password(), oninput: (e) => setPassword(e.target.value), required: true }),
        password().length > 0 ? div({ class: css('_flex _aic _gap2 _mt1') },
          div({ class: css('_flex _gap1 _flex1') },
            ...Array(3).fill(0).map((_, i) =>
              div({ class: css(`_h1 _flex1 _r1 ${i < strength().level ? `_bg${strength().color}` : '_bgBorder'}`) })
            )
          ),
          span({ class: css(`_textsm _fg${strength().color}`) }, strength().label)
        ) : null
      ),
      Button({ type: 'submit', variant: 'primary', class: css('_wfull') }, 'Create Account')
    ),
    p({ class: css('_tc _mt6 _textsm _fgmuted') },
      'Already have an account? ',
      link({ href: '/login', class: css('_fgPrimary _font500') }, 'Sign in')
    )
  );
}

