function ResetPasswordForm({ onSubmit }) {
  const { div, form, h1, p, input, label } = tags;
  const [password, setPassword] = createSignal('');
  const [confirm, setConfirm] = createSignal('');
  const [error, setError] = createSignal('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (password() !== confirm()) { setError('Passwords do not match'); return; }
    if (password().length < 8) { setError('Password must be at least 8 characters'); return; }
    onSubmit({ password: password() });
  };

  return div({ class: css('carbon-card _p8 _maxw[400px] _wfull') },
    div({ class: css('_tc _mb6') },
      h1({ class: css('_heading3 _mb2') }, 'Set new password'),
      p({ class: css('_fgmuted') }, 'Enter your new password below')
    ),
    form({ class: css('_flex _col _gap4'), onsubmit: handleSubmit },
      error() ? div({ class: css('_p3 _r2 _bgDanger/10 _fgDanger _textsm') }, error()) : null,
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'New Password'),
        input({ type: 'password', class: css('carbon-input _p2 _r2'), value: password(), oninput: (e) => setPassword(e.target.value), required: true })
      ),
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Confirm Password'),
        input({ type: 'password', class: css('carbon-input _p2 _r2'), value: confirm(), oninput: (e) => setConfirm(e.target.value), required: true })
      ),
      Button({ type: 'submit', variant: 'primary', class: css('_wfull') }, 'Reset Password')
    )
  );
}

