function MFASetupForm({ qrCode, secret, onVerify }) {
  const { div, form, h1, p, input, label, img, code } = tags;
  const [verifyCode, setVerifyCode] = createSignal('');

  return div({ class: css('carbon-card _p8 _maxw[400px] _wfull') },
    div({ class: css('_tc _mb6') },
      h1({ class: css('_heading3 _mb2') }, 'Set up 2FA'),
      p({ class: css('_fgmuted') }, 'Scan this QR code with your authenticator app')
    ),
    div({ class: css('_flex _jcc _mb6') },
      img({ src: qrCode, alt: 'QR Code', class: css('_w48 _h48') })
    ),
    div({ class: css('_tc _mb6') },
      p({ class: css('_textsm _fgmuted _mb2') }, "Can't scan? Enter this code manually:"),
      code({ class: css('carbon-code _p2 _r1 _textsm') }, secret)
    ),
    form({ class: css('_flex _col _gap4'), onsubmit: (e) => { e.preventDefault(); onVerify(verifyCode()); } },
      div({ class: css('_flex _col _gap1') },
        label({ class: css('_textsm _font500') }, 'Verification Code'),
        input({ type: 'text', class: css('carbon-input _p2 _r2 _tc _tracking[0.5em]'), maxlength: 6, value: verifyCode(), oninput: (e) => setVerifyCode(e.target.value), placeholder: '000000' })
      ),
      Button({ type: 'submit', variant: 'primary', class: css('_wfull') }, 'Verify & Enable')
    )
  );
}

